// Delete all the data between start and end date for a given sensor
func (s *service) Delete(sensorID string, start, end time.Time) error {
	datas := s.datas.FindForDates(SensorParams{SensorID: &sensorID}, start, end)
	// Get the DailyData before and after the first and last date

	for _, data := range datas {
		startTruncated := start.Truncate(24 * time.Hour)
		endTruncated := end.Truncate(24 * time.Hour)

		// If start and end are on the same day and both match current data's day
		if startTruncated.Equal(endTruncated) && data.Date.Equal(startTruncated) {
			// Remove only entries within the time range
			data.RemoveRange(
				start.Hour(), start.Minute(), start.Second(),
				end.Hour(), end.Minute(), end.Second(),
			)

			if len(data.Data) == 0 {
				s.datas.Delete(sensorID, data.Date, data.Date)
			} else {
				s.datas.Store(data)
			}
			continue
		}

		// Handle start day
		if data.Date.Equal(startTruncated) {
			data.RemoveAfterOrEqual(start.Hour(), start.Minute(), start.Second())

			if len(data.Data) == 0 {
				s.datas.Delete(sensorID, data.Date, data.Date)
			} else {
				s.datas.Store(data)
			}
			continue
		}

		// Handle end day
		if data.Date.Equal(endTruncated) {
			data.RemoveBeforeOrEqual(end.Hour(), end.Minute(), end.Second())

			if len(data.Data) == 0 {
				s.datas.Delete(sensorID, data.Date, data.Date)
			} else {
				s.datas.Store(data)
			}
			continue
		}
	}
