package data

import (
	"fmt"
	"sort"
	"time"
)

// Service is the interface that provides methods to implements CRUD for data
type Service interface {
	Create(rawDatas []*RawData) error
	// Update(sensorID string, date time.Time, index, value *float64)
	Delete(sensorID string, start, end time.Time) error
}

type service struct {
	datas Repository
}

// Delete all the data between start and end date for a given sensor
func (s *service) Delete(sensorID string, start, end time.Time) error {
	datas := s.datas.FindForDates(SensorParams{SensorID: &sensorID}, start, end)
	// Get the DailyData before and after the first and last date

	for _, data := range datas {
		if data.Date.Equal(start.Truncate(24 * time.Hour)) {
			data.RemoveAfterOrEqual(start.Hour(), start.Minute(), start.Second())

			if len(data.Data) == 0 {
				s.datas.Delete(sensorID, data.Date, data.Date)
			} else {
				s.datas.Store(data)
			}
			continue
		}

		if data.Date.Equal(end.Truncate(24 * time.Hour)) {
			data.RemoveBeforeOrEqual(end.Hour(), end.Minute(), end.Second())

			if len(data.Data) == 0 {
				s.datas.Delete(sensorID, data.Date, data.Date)
			} else {
				s.datas.Store(data)
			}

			continue
		}
	}

	start = start.Truncate(24 * time.Hour)
	end = end.Truncate(24 * time.Hour)

	startFullDay := start.Truncate(24 * time.Hour).Add(24 * time.Hour)
	endFullDay := end.Truncate(24 * time.Hour).Add(-24 * time.Hour)

	if startFullDay.Before(endFullDay) || startFullDay.Equal(endFullDay) {
		s.datas.Delete(sensorID, startFullDay, endFullDay)
	}

	// Update first data after or equal end date
	nextData := s.datas.FindNext(sensorID, end.Add(-24*time.Hour))

	if nextData != nil {
		prevData := s.datas.FindPrev(sensorID, nextData.Date)
		lastIdx := prevData.getLastIdx()

		nextData.UpdateFirst(lastIdx, nil, nextData.UnitPrice, nextData.Date)
		s.datas.Store(nextData)
	}

	return nil
}

// Create an entry for the raw datas. All the  data are related to the same sensor.
func (s *service) Create(rawDatas []*RawData) error {
	if len(rawDatas) == 0 {
		return fmt.Errorf("no data to insert into DB")
	}

	// Sort rawDatas by date
	sort.SliceStable(rawDatas, func(i, j int) bool { return rawDatas[i].Date.Time.Before(rawDatas[j].Date.Time) })

	first := rawDatas[0]
	last := rawDatas[len(rawDatas)-1]

	// Get all DailyData for the sensor between the first and last date
  dbDatasSlice := s.datas.FindForDates(SensorParams{SensorID: &first.SensorID}, first.Date.Time, last.Date.Time)

	// Get the DailyData before and after the first and last date
	prevDBData := s.datas.FindPrev(first.SensorID, first.Date.Time)
	nextDBData := s.datas.FindNext(first.SensorID, last.Date.Time)

	if prevDBData != nil {
		dbDatasSlice = append(dbDatasSlice, prevDBData)
	}

	if nextDBData != nil {
		dbDatasSlice = append(dbDatasSlice, nextDBData)
	}

	// Sort dbDatas by date
	var dates []time.Time
	dbDatas := make(map[string]*DailyData)
	for _, _dbData := range dbDatasSlice {
		dbDatas[_dbData.Date.UTC().String()] = _dbData
		dates = append(dates, _dbData.Date)
	}
	sortDates(dates)

	// IDEA: If we want to improve speed of this part it is possible to only save
	// all DailyData at the end of the forloop
	for _, raw := range rawDatas {
		day := raw.Date.Truncate(24 * time.Hour)
		current := dbDatas[day.String()]

		var isNew bool // Tell if the current DailyData juste have been created

		if current == nil {
			current = &DailyData{
				SensorID: raw.SensorID,
				Date:     day,
			}
			isNew = true
			dbDatas[day.String()] = current
			dates = append(dates, day)
			sortDates(dates)
		}

		if raw.Value != nil {
			current.AddUpdate(raw.Value, nil, nil, nil, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)
			s.datas.Store(current)
			continue
		} else if raw.Index != nil {
			var lastIdx *float64
			prevDate, nextDate := prevNextDates(dates, day)
			if isNew {
				if prevDate != nil {
					prevData := dbDatas[prevDate.String()]

					if prevData != nil {
						lastIdx = prevData.Index
					}
				}

				current.AddUpdate(nil, raw.Index, lastIdx, raw.Factor, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)
				s.datas.Store(current)

				if nextDate != nil {
					nextData := dbDatas[nextDate.String()]
					err := nextData.UpdateFirst(raw.Index, raw.Factor, raw.UnitPrice, raw.Date.Time)
					if err != nil {
						return err
					}
					s.datas.Store(nextData)
				}
				continue
			}

			// Case current already exists
			firstDT, lastDT := current.FirstLastDT()

			if raw.Date.Before(firstDT) || raw.Date.Equal(firstDT) {
				if prevDate != nil {
					prevData := dbDatas[prevDate.String()]
					if prevData != nil {
						lastIdx = prevData.Index
					}
				}
			}

			if raw.Date.After(lastDT) || raw.Date.Equal(lastDT) {
				if nextDate != nil {
					nextData := dbDatas[nextDate.String()]
					err := nextData.UpdateFirst(raw.Index, raw.Factor, raw.UnitPrice, raw.Date.Time)

					if err != nil {
						return err
					}

					s.datas.Store(nextData)
				}
			}

			err := current.AddUpdate(raw.Value, raw.Index, lastIdx, raw.Factor, raw.UnitPrice, raw.Date.Time, raw.Threshold, raw.Coef)

			if err != nil {
				return err
			}

			s.datas.Store(current)
		} else {
			return fmt.Errorf("there is no value or index for sensor %s for date %v", raw.SensorID, raw.Date.Time)
		}
	}

	return nil
}

func sortDates(dates []time.Time) {
	sort.SliceStable(dates, func(i int, j int) bool {
		return dates[i].Before(dates[j])
	})
}

// prevNextDates return the date previous and next dates of a given from a list
// of dates
func prevNextDates(dates []time.Time, current time.Time) (prev, next *time.Time) {
	for idx, date := range dates {
		if !date.Equal(current) {
			continue
		}

		if idx > 0 {
			prev = &dates[idx-1]
		}

		if idx < len(dates)-1 {
			next = &dates[idx+1]
		}

		break
	}

	return
}

// NewService creates a dataCRUD service with necessary dependencies.
func NewService(datas Repository) Service {
	return &service{
		datas: datas,
	}
}
