// DeleteAt removes a single data point at the specified datetime
func (s *service) DeleteAt(sensorID string, datetime time.Time) error {
	// Get the day this datetime belongs to
	day := datetime.Truncate(24 * time.Hour)

	// Find the data for this day
	data := s.datas.FindForDates(SensorParams{SensorID: &sensorID}, day, day.Add(24*time.Hour-time.Second))

	if len(data) == 0 {
		return fmt.Errorf("no data found for sensor %s at %v", sensorID, datetime)
	}

	for _, dayData := range data {
		// If this is the right day
		if dayData.Date.Equal(day) {
			// Remove the specific entry
			dayData.RemoveAtDateTime(datetime.Hour(), datetime.Minute(), datetime.Second())

			// If no data left, delete the entire day's record
			if len(dayData.Data) == 0 {
				s.datas.Delete(sensorID, dayData.Date, dayData.Date)
			} else {
				// Otherwise store the updated record
				s.datas.Store(dayData)
			}

			return nil
		}
	}

	return fmt.Errorf("no data found for sensor %s at exact time %v", sensorID, datetime)
}
