// HourlyData set.
type HourlyData struct {
	Hour  int            `bson:"hour" json:"hour"`
	Data  []*MinutlyData `bson:"data" json:"data"`
	Datum `bson:",inline"`
}

// MinutlyData set.
type MinutlyData struct {
	Minute int             `bson:"minute"`
	Data   []*SecondlyData `bson:"data"`
	Datum  `bson:",inline"`
}

// SecondlyData set.
type SecondlyData struct {
	Second int `bson:"second"`
	Datum  `bson:",inline"`
}

// DailyData is the upper leve structure wich embed HourlyData.
type DailyData struct {
	SensorID string        `bson:"sensorID" json:"sensorID"`
	Date     time.Time     `bson:"date" json:"date"`
	Data     []*HourlyData `bson:"data" json:"data"`
	Datum    `bson:",inline"`
}

