}

func (hd *HourlyData) RemoveBeforeOrEqual(minute, second int) {
	isModified := false

	// Sort Data by minute
	sort.SliceStable(hd.Data, func(i, j int) bool { return hd.Data[i].Minute < hd.Data[j].Minute })

	for mIdx := len(hd.Data) - 1; mIdx >= 0; mIdx-- {
		md := hd.Data[mIdx]

		if md.Minute <= minute {
			startIdx := mIdx + 1
			isModified = true

			if md.Minute == minute {
				md.RemoveBeforeOrEqual(second)

				// If there is still data left, keep this minutly data
				if len(md.Data) != 0 {
					startIdx--
				}
			}

			if startIdx > len(hd.Data)-1 {
				hd.Data = []*MinutlyData{}
			} else {
