// AddUpdate add or update entry for MinutlyData
func (md *MinutlyData) AddUpdate(value, index, lastIdx, factor, unitPrice *float64, date time.Time, threshold *int64, coef *float64) (deltaValue, deltaPrice float64, isCreation, isLastData, updateNext bool, err error) {
	var sd, nextSD *SecondlyData
	second := date.Second()

	sort.SliceStable(md.Data, func(i, j int) bool { return md.Data[i].Second < md.Data[j].Second })

	for _idx, _sd := range md.Data {
		if second == _sd.Second {
			sd = _sd

			if _idx == len(md.Data)-1 {
				isLastData = true
			} else {
				nextSD = md.Data[_idx+1]
			}

			break
		}

		if second < _sd.Second {
			nextSD = _sd
			break
		}

		// if lastIdx == nil || (_sd.Index != nil && *lastIdx < *_sd.Index) {
		// 	lastIdx = _sd.Index
		// }
		lastIdx = _sd.Index
	}

	if sd == nil {
		isCreation = true
		sd = &SecondlyData{Second: second, Datum: Datum{Nb: 1}}

		if sdLength := len(md.Data); sdLength == 0 || sd.Second > md.Data[sdLength-1].Second {
			isLastData = true
		}

		md.Data = append(md.Data, sd)
		md.Nb++
	}

	deltaValue, deltaPrice, err = sd.Update(value, index, lastIdx, factor, unitPrice, threshold, coef)

	if err != nil {
		return
	}

	// Manage case when data  which is not last is created/updated using index.
	// In this case the next data.
	if index != nil {
		if nextSD == nil {
			updateNext = true
		} else {
			nextDeltaValue, nextDeltaPrice, nextErr := nextSD.Update(nextSD.Value, nextSD.Index, index, factor, unitPrice, threshold, nextSD.Coef)

			if nextErr != nil {
				return 0, 0, false, false, false, err
			}

			deltaValue += nextDeltaValue
			deltaPrice += nextDeltaPrice
		}
	}

	if md.Value == nil {
		md.Value = new(float64)
	}

	*md.Value += deltaValue

	if unitPrice != nil {
		if md.Price == nil {
			md.Price = new(float64)
		}
		*md.Price += deltaPrice
	}

	if threshold != nil && (md.Threshold == nil || *threshold > *md.Threshold) {
		md.Threshold = threshold
	}

	if isLastData {
		md.Index = index
	}

	// Set or update coef
	var data []Datum
	for _, sd := range md.Data {
		data = append(data, sd.Datum)
	}
	md.Coef = recomputeCoef(data)

	return
}

