func computeDatumFromSubset(subset map[int]Datum) (datum Datum) {
	keys := sortedKeys(subset)

	for _, key := range keys {
		subDatum := subset[key]

		datum.Nb++

		if subDatum.Value != nil {
			if datum.Value == nil {
				datum.Value = new(float64)
			}

			*datum.Value += *subDatum.Value
		}

		if subDatum.Price != nil {
			if datum.Price == nil {
				datum.Price = new(float64)
			}

			*datum.Price += *subDatum.Price
		}

		if subDatum.CO2 != nil {
			if datum.CO2 == nil {
				datum.CO2 = new(float64)
			}

			*datum.CO2 += *subDatum.CO2
		}

		if subDatum.Index != nil {
			if datum.Index == nil {
				datum.Index = new(float64)
			}
			*datum.Index = *subDatum.Index
		}
	}

	return
}

func sortedKeys(m map[int]Datum) []int {
	keys := make([]int, len(m))
	i := 0
	for k := range m {
		keys[i] = k
		i++
	}
	sort.Ints(keys)
	return keys
}

func recomputeCoef(data []Datum) *float64 {
	value := 0.0
	valueByCoef := 0.0

	for _, d := range data {
		if d.Value != nil && d.Coef != nil {
			value += *d.Value
			valueByCoef += *d.Value * *d.Coef
		}
	}

	if valueByCoef != 0.0 && value != 0.0 {
		coef := new(float64)
		*coef = valueByCoef / value
		return coef
	}

	return nil
}
