// RemoveAtDateTime removes a single entry at the specific hour, minute, second
func (d *DailyData) RemoveAtDateTime(hour, minute, second int) bool {
	isModified := false
	targetSeconds := hour*3600 + minute*60 + second

	// Sort Data by hour
	sort.SliceStable(d.Data, func(i, j int) bool { return d.Data[i].Hour < d.Data[j].Hour })

	for hIdx, hd := range d.Data {
		dataHour := hd.Hour
		hourSeconds := dataHour * 3600

		// If this hour contains our target
		if hourSeconds <= targetSeconds && hourSeconds+3599 >= targetSeconds {
			minuteToFind := minute
			secondToFind := second

			// Find the minute entry
			sort.SliceStable(hd.Data, func(i, j int) bool { return hd.Data[i].Minute < hd.Data[j].Minute })

			for mIdx, md := range hd.Data {
				if md.Minute == minuteToFind {
					// Find the second entry
					sort.SliceStable(md.Data, func(i, j int) bool { return md.Data[i].Second < md.Data[j].Second })

					for sIdx, sd := range md.Data {
						if sd.Second == secondToFind {
							// Remove this specific second entry
							md.Data = append(md.Data[:sIdx], md.Data[sIdx+1:]...)
							isModified = true

							// If no more seconds, remove the minute entry
							if len(md.Data) == 0 {
								hd.Data = append(hd.Data[:mIdx], hd.Data[mIdx+1:]...)

								// If no more minutes, remove the hour entry
								if len(hd.Data) == 0 {
									d.Data = append(d.Data[:hIdx], d.Data[hIdx+1:]...)
								} else {
									// Recompute the hour data
									hd.recompute(true)
								}
							} else {
								// Recompute the minute data
								md.recompute()
								// And the hour data
								hd.recompute(false)
							}

							break
						}
					}
					break
				}
			}
			break
		}
	}

	// If we modified anything, recompute the daily data
	if isModified {
		d.recompute(false)
	}

	return isModified
