// Datum represents the basics of the data.
type Datum struct {
	Price     *float64 `bson:"price" json:"price"`
	UnitPrice *float64 `bson:"unitPrice" json:"-"`
	Threshold *int64   `bson:"threshold" json:"threshold"`
	Value     *float64 `bson:"value" json:"value"`
	Index     *float64 `bson:"index" json:"index"`
	CO2       *float64 `bson:"co2" json:"co2"`
	Coef      *float64 `bson:"coef" json:"-"`
	Nb        int      `bson:"nb" json:"-"`
}

// Round the different fields of Datum struct
func (d *Datum) Round() {
	if d.Value != nil {
		val := utils.Round(*d.Value, 0.5, 5)
		d.Value = &val
	}

	if d.Index != nil {
		idx := utils.Round(*d.Index, 0.5, 3)
		d.Index = &idx
	}

	if d.Price != nil {
		price := utils.Round(*d.Price, 0.5, 5)
		d.Price = &price
	}

	if d.CO2 != nil {
		co2 := utils.Round(*d.CO2, 0.5, 3)
		d.CO2 = &co2
	}
}

// Update a datum struct.
// If a value and an index is provided, only the value is used.
func (d *Datum) Update(value, index, lastIdx, factor, unitPrice *float64, threshold *int64, coef *float64) (deltaValue, deltaPrice float64, err error) {
	var prevValue float64
	var prevPrice float64
	d.UnitPrice = unitPrice

	if d.Value == nil {
		d.Value = new(float64)
	} else {
		prevValue = *d.Value
	}

	if d.Price != nil {
		prevPrice = *d.Price
	}

	switch {
	case value == nil && index == nil:
		return 0, 0, fmt.Errorf("index and Values are null")
	case index != nil:
		d.Index = new(float64)
		*d.Index = *index
		if lastIdx != nil && *index-*lastIdx > 0 {
			*d.Value = *index - *lastIdx
		} else {
			*d.Value = 0
		}
	case value != nil:
		*d.Value = *value
		d.Index = nil
	}

	if factor != nil {
		*d.Value *= *factor
	}

	if d.UnitPrice != nil {
		d.Price = new(float64)
		*d.Price = *d.Value * *unitPrice

		deltaPrice = *d.Price - prevPrice
	}

	if threshold != nil && (d.Threshold == nil || *threshold > *d.Threshold) {
		d.Threshold = threshold
	}

	d.Coef = coef

	deltaValue = *d.Value - prevValue

	return deltaValue, deltaPrice, nil
}

