// FirstLastDT return the datetime of the first and last entry in the DailyData
func (dd *DailyData) FirstLastDT() (first, last time.Time) {
	first = dd.Date
	last = dd.Date

	var minHD, maxHD *HourlyData
	for _, hd := range dd.Data {
		if minHD == nil || hd.Hour < minHD.Hour {
			minHD = hd
		}

		if maxHD == nil || hd.Hour > maxHD.Hour {
			maxHD = hd
		}
	}

	if minHD != nil {
		minMD := minHD.MinMD()
		minSD := minMD.MinSD()

		first = first.Add(time.Duration(minHD.Hour)*time.Hour +
			time.Duration(minMD.Minute)*time.Minute +
			time.Duration(minSD.Second)*time.Second)
	}

	if maxHD != nil {
		maxMD := maxHD.MaxMD()
		maxSD := maxMD.MaxSD()

		last = last.Add(time.Duration(maxHD.Hour)*time.Hour +
			time.Duration(maxMD.Minute)*time.Minute +
			time.Duration(maxSD.Second)*time.Second)
	}

	return first, last
}

func (dd *DailyData) getLastIdx() *float64 {
	if len(dd.Data) == 0 {
		return nil
	}

	hd := dd.Data[len(dd.Data)-1]

	if len(hd.Data) == 0 {
		return nil
	}

	// Sort hd.Data by minute
	sort.SliceStable(hd.Data, func(i, j int) bool {
		return hd.Data[i].Minute < hd.Data[j].Minute
	})

	md := hd.Data[len(hd.Data)-1]

	// sort md.Data by second
	sort.SliceStable(md.Data, func(i, j int) bool {
		return md.Data[i].Second < md.Data[j].Second
	})

	if len(md.Data) == 0 {
		return nil
	}

	sd := md.Data[len(md.Data)-1]

	return sd.Index
}

func (dd *DailyData) getFirstIdx() *float64 {
	if len(dd.Data) == 0 {
		return nil
	}

	// Sort hd.Data by minute
	sort.SliceStable(dd.Data, func(i, j int) bool {
		return dd.Data[i].Hour < dd.Data[j].Hour
	})

	hd := dd.Data[0]

	if len(hd.Data) == 0 {
		return nil
	}

	// Sort hd.Data by minute
	sort.SliceStable(hd.Data, func(i, j int) bool {
		return hd.Data[i].Minute < hd.Data[j].Minute
	})

	md := hd.Data[0]

	// sort md.Data by second
	sort.SliceStable(md.Data, func(i, j int) bool {
		return md.Data[i].Second < md.Data[j].Second
	})

	if len(md.Data) == 0 {
		return nil
	}

	sd := md.Data[0]

	return sd.Index
}

// UpdateFirst update first data of the daily data. It is used when a data is added
// the previous day with an index
func (dd *DailyData) UpdateFirst(lastIdx, factor, unitPrice *float64, _date time.Time) error {
	if len(dd.Data) == 0 || len(dd.Data[0].Data) == 0 || len(dd.Data[0].Data[0].Data) == 0 {
		return fmt.Errorf("can't update first data for sensor #%s and date %v", dd.SensorID, dd.Date)
	}

	sort.SliceStable(dd.Data, func(i, j int) bool { return dd.Data[i].Hour < dd.Data[j].Hour })

	hd := dd.Data[0]
	sort.SliceStable(hd.Data, func(i, j int) bool { return hd.Data[i].Minute < hd.Data[j].Minute })
	md := hd.Data[0]
	sort.SliceStable(md.Data, func(i, j int) bool { return md.Data[i].Second < md.Data[j].Second })
	sd := md.Data[0]

	deltaValue, deltaPrice, err := sd.Update(sd.Value, sd.Index, lastIdx, factor, unitPrice, nil, sd.Coef)

	if err != nil {
		return err
	}

	// Update computed values and prices
	*md.Value += deltaValue
	*hd.Value += deltaValue
	*dd.Value += deltaValue

	if deltaPrice != 0 {
		if md.Price == nil {
			md.Price = new(float64)
		}
		if hd.Price == nil {
			hd.Price = new(float64)
		}
		if dd.Price == nil {
			dd.Price = new(float64)
		}

		*md.Price += deltaPrice
		*hd.Price += deltaPrice
		*dd.Price += deltaPrice
	}

	return nil
}

// AddUpdate add or update entry for the DailyData
func (dd *DailyData) AddUpdate(value, index, lastIdx, factor, unitPrice *float64, date time.Time, threshold *int64, coef *float64) error {
	var hd, nextHD *HourlyData
	hour := date.Hour()
	var isLastHour bool

	sort.SliceStable(dd.Data, func(i, j int) bool { return dd.Data[i].Hour < dd.Data[j].Hour })

	for _idx, _hd := range dd.Data {
		if hour == _hd.Hour {
			hd = _hd

			if _idx == len(dd.Data)-1 {
				isLastHour = true
			} else {
				nextHD = dd.Data[_idx+1]
			}
			break
		}

		if hour < _hd.Hour {
			nextHD = _hd
			break
		}

		lastIdx = _hd.Index
		// if lastIdx == nil || (_hd.Index != nil && *lastIdx < *_hd.Index) {
		// lastIdx = _hd.Index
		// }
	}

	if hd == nil {
		if lenData := len(dd.Data); lenData == 0 || (lenData > 0 && dd.Data[lenData-1].Hour <= hour) {
			isLastHour = true
		}
		hd = &HourlyData{Hour: hour}
		dd.Data = append(dd.Data, hd)
	}

	deltaValue, deltaPrice, isCreation, isLastMinute, updateNext, err := hd.AddUpdate(value, index, lastIdx, factor, unitPrice, date, threshold, coef)

	if err != nil {
		return err
	}

	if updateNext && nextHD != nil {
		deltaValueNext, deltaPriceNext, errNext := nextHD.UpdateFirst(index, factor, unitPrice, date)

		if errNext != nil {
			return errNext
		}

		deltaValue += deltaValueNext
		deltaPrice += deltaPriceNext
	}

	if dd.Value == nil {
		dd.Value = new(float64)
	}

	*dd.Value += deltaValue

	if unitPrice != nil {
		if dd.Price == nil {
			dd.Price = new(float64)
		}
		*dd.Price += deltaPrice
	}

	// Set or update coef
	var data []Datum
	for _, hd := range dd.Data {
		data = append(data, hd.Datum)
	}
	dd.Coef = recomputeCoef(data)

	if threshold != nil && (dd.Threshold == nil || *threshold > *dd.Threshold) {
		dd.Threshold = threshold
	}

	if isCreation {
		dd.Nb++
	}

	if isLastHour && isLastMinute {
		dd.Index = index
	}

	return nil
}

// Round values, prices, indexes to avoid floating problem with infinite decimal
func (dd *DailyData) Round() {
	dd.Datum.Round()

	for _, hd := range dd.Data {
		hd.Datum.Round()

		for _, md := range hd.Data {
			md.Datum.Round()

			for _, sd := range md.Data {
				sd.Datum.Round()
			}
		}
	}
}

// RemoveBefore remove data before the given time
func (dd *DailyData) RemoveBefore(hour, minute, second int) {
	isModified := false

	// sort Data by hour
	sort.SliceStable(dd.Data, func(i, j int) bool { return dd.Data[i].Hour < dd.Data[j].Hour })

	for hIdx := len(dd.Data) - 1; hIdx >= 0; hIdx-- {
		hd := dd.Data[hIdx]

		if hd.Hour < hour {
			isModified = true
			dd.Data = append(dd.Data[:hIdx], dd.Data[hIdx+1:]...)
			continue
		}

		if hd.Hour == hour {
			isModified = true
			hd.RemoveBefore(minute, second)
		}
	}

	if isModified {
		dd.recompute(false)
	}
}

// RemoveAfter remove data after the given time
func (dd *DailyData) RemoveAfter(hour, minute, second int) {
	isModified := false

	// sort Data by hour
	sort.SliceStable(dd.Data, func(i, j int) bool { return dd.Data[i].Hour < dd.Data[j].Hour })

	for hIdx := 0; hIdx < len(dd.Data); hIdx++ {
		hd := dd.Data[hIdx]

		if hd.Hour < hour {
			isModified = true
			dd.Data = append(dd.Data[:hIdx], dd.Data[hIdx+1:]...)
			continue
		}

		if hd.Hour == hour {
			isModified = true
			hd.RemoveAfter(minute, second)
		}
	}

	if isModified {
		dd.recompute(false)
	}
}

func (dd *DailyData) RemoveBeforeOrEqual(hour, minute, second int) {
	isModified := false

	// sort Data by hour
	sort.SliceStable(dd.Data, func(i, j int) bool { return dd.Data[i].Hour < dd.Data[j].Hour })

	for hIdx := len(dd.Data) - 1; hIdx >= 0; hIdx-- {
		hd := dd.Data[hIdx]

		if hd.Hour <= hour {
			startIdx := hIdx + 1
			isModified = true

			if hd.Hour == hour {
				hd.RemoveBeforeOrEqual(minute, second)

				// If there is still data left, keep this the hourly data
				if len(hd.Data) != 0 {
					startIdx--
				}
			}

			if startIdx > len(dd.Data)-1 {
				dd.Data = []*HourlyData{}
			} else {
				dd.Data = dd.Data[startIdx:]
			}

			break
		}
	}

	if isModified {
		dd.recompute(true)
	}
}

func (dd *DailyData) RemoveAfterOrEqual(hour, minute, second int) {
	isModified := false

	// sort Data by hour
	sort.SliceStable(dd.Data, func(i, j int) bool { return dd.Data[i].Hour < dd.Data[j].Hour })

	for hIdx := 0; hIdx < len(dd.Data); hIdx++ {
		hd := dd.Data[hIdx]

		if hd.Hour >= hour {
			isModified = true
			removeIdx := hIdx

			if hd.Hour == hour {
				hd.RemoveAfterOrEqual(minute, second)

				// If there is still data left, keep this the hourly data
				if len(hd.Data) != 0 {
					removeIdx++
				}
			}
			dd.Data = dd.Data[:removeIdx]
			break
		}
	}

	if isModified {
		dd.recompute(true)
	}
}

// recompute its data, value, index, price, and number of elements
func (dd *DailyData) recompute(recomputeSubset bool) {
	subset := make(map[int]Datum)

	for _, hd := range dd.Data {
		if recomputeSubset {
			hd.recompute(true)
		}
		subset[hd.Hour] = hd.Datum
	}

	dd.Datum = computeDatumFromSubset(subset)
}

/*--------------------------------------------------------------------------------------------------------------------*\
	HourlyData methods
\*--------------------------------------------------------------------------------------------------------------------*/

// MinMD return the MinutlyData with the datetime the oldest
func (hd *HourlyData) MinMD() *MinutlyData {
	var minMD *MinutlyData
	for _, md := range hd.Data {
		if minMD == nil || minMD.Minute > md.Minute {
			minMD = md
		}
	}

	return minMD
}

// MaxMD return the MinutlyData with the datetime the newest
func (hd *HourlyData) MaxMD() *MinutlyData {
	var maxMD *MinutlyData
	for _, md := range hd.Data {
		if maxMD == nil || maxMD.Minute < md.Minute {
			maxMD = md
		}
	}

	return maxMD
}

// UpdateFirst update first data of the hourly data. It is used when a data is added
// the previous hourly with an index
func (hd *HourlyData) UpdateFirst(lastIdx, factor, unitPrice *float64, date time.Time) (deltaValue, deltaPrice float64, err error) {
	if len(hd.Data) == 0 || len(hd.Data[0].Data) == 0 {
		return 0, 0, fmt.Errorf("can't update first data for date %v", date)
	}

	sort.SliceStable(hd.Data, func(i, j int) bool { return hd.Data[i].Minute < hd.Data[j].Minute })
	md := hd.Data[0]
	sort.SliceStable(md.Data, func(i, j int) bool { return md.Data[i].Second < md.Data[j].Second })
	sd := md.Data[0]

	deltaValue, deltaPrice, err = sd.Update(sd.Value, sd.Index, lastIdx, factor, unitPrice, nil, sd.Coef)

	if err != nil {
		return 0, 0, err
	}

	// Update computed values and prices
	*hd.Value += deltaValue
	*md.Value += deltaValue

	if deltaPrice != 0 {
		if md.Price == nil {
			md.Price = new(float64)
		}

		if hd.Price == nil {
			hd.Price = new(float64)
		}

		*hd.Price += deltaPrice
		*md.Price += deltaPrice
	}

	return
}

// AddUpdate add or update entry for the HourlyData
func (hd *HourlyData) AddUpdate(value, index, lastIdx, factor, unitPrice *float64, date time.Time, threshold *int64, coef *float64) (deltaValue, deltaPrice float64, isCreation, isLastData, updateNext bool, err error) {
	var md, nextMD *MinutlyData
	var isLastMinute, isLastSecond bool
	minute := date.Minute()

	sort.SliceStable(hd.Data, func(i, j int) bool { return hd.Data[i].Minute < hd.Data[j].Minute })

	for _idx, _md := range hd.Data {
		if minute == _md.Minute {
			md = _md

			if _idx == len(hd.Data)-1 {
				isLastMinute = true
			} else {
				nextMD = hd.Data[_idx+1]
			}

			break
		}

		if minute < _md.Minute {
			nextMD = _md
			break
		}

		// if lastIdx == nil || (_md.Index != nil && *lastIdx < *_md.Index) {
		// 	lastIdx = _md.Index
		// }
		lastIdx = _md.Index
	}

	if md == nil {
		if lenData := len(hd.Data); lenData == 0 || (lenData > 0 && hd.Data[lenData-1].Minute <= minute) {
			isLastMinute = true
		}

		md = &MinutlyData{Minute: minute}
		hd.Data = append(hd.Data, md)
	}

	deltaValue, deltaPrice, isCreation, isLastSecond, updateNext, err = md.AddUpdate(value, index, lastIdx, factor, unitPrice, date, threshold, coef)

	if err != nil {
		return 0, 0, false, false, false, err
	}

	if updateNext && nextMD != nil && index != nil {
		updateNext = false
		deltaValueNext, deltaPriceNext, errNext := nextMD.UpdateFirst(index, factor, unitPrice, date)

		if errNext != nil {
			return 0, 0, false, false, false, errNext
		}

		deltaValue += deltaValueNext
		deltaPrice += deltaPriceNext
	}

	if hd.Value == nil {
		hd.Value = new(float64)
	}

	*hd.Value += deltaValue

	if unitPrice != nil {
		if hd.Price == nil {
			hd.Price = new(float64)
		}
		*hd.Price += deltaPrice
	}

	// Set or update coef
	var data []Datum
	for _, md := range hd.Data {
		data = append(data, md.Datum)
	}
	hd.Coef = recomputeCoef(data)

	if threshold != nil && (hd.Threshold == nil || *threshold > *hd.Threshold) {
		hd.Threshold = threshold
	}

	if isCreation {
		hd.Nb++
	}

	if isLastMinute && isLastSecond {
		hd.Index = index
		isLastData = true
	}

	return
}

